1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	};
14	
15	type Item = {
16	  type: string;
17	  material?: string;
18	  enchantment?: number;
19	  cursed?: boolean;
20	};
21	type Step = { op: "quote"; items: Item[] };
22	type Scenario = { customer: unknown; steps: Step[] };
23	
24	const componentGroupPremium = (count: number): number =>
25	  count === COMPONENT_BLOCK_SIZE
26	    ? COMPONENT_BLOCK_PREMIUM
27	    : count * COMPONENT_BASE_PREMIUM;
28	
29	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
30	
31	const mainItemPremium = (item: Item): number => {
32	  const base = BASE_PREMIUM_BY_TYPE[item.type];
33	  if (!item.cursed) return base;
34	  const curse = base * CURSE_SURCHARGE_RATE;
35	  const firstInsurance = base * FIRST_INSURANCE_RATE;
36	  return base + curse + firstInsurance;
37	};
38	
39	const countByType = (items: Item[]): Map<string, number> =>
40	  items.reduce(
41	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
42	    new Map<string, number>(),
43	  );
44	
45	const sumComponentPremiums = (components: Item[]): number =>
46	  [...countByType(components).values()]
47	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
48	
49	const sumBasePremiums = (items: Item[]): number => {
50	  const mains = items.filter(isMainItem);
51	  const components = items.filter((i) => !isMainItem(i));
52	  const mainsSum = mains.reduce((sum, item) => sum + mainItemPremium(item), 0);
53	  return mainsSum + sumComponentPremiums(components);
54	};
55	
56	const quotePremiumFor = (step: Step): { premium: number } => ({
57	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
58	});
59	
60	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
61	  results: scenario.steps.map(quotePremiumFor),
62	});
